    Stream = 1,
    Datagram = 2,
}

impl TryFrom<u32> for SocketType {
    type Error = Error;

    fn try_from(value: u32) -> Result<Self> {
        match value {
            1 => Ok(SocketType::Stream),
            2 => Ok(SocketType::Datagram),
            _ => Err(Error::new(
                ErrorKind::InvalidData,
                "unknown value for socket type",
            )),
        }
